Pour réaliser l'effet désiré avec vos deux éléments `h1`, il faut ajuster le script pour qu'il gère correctement l'affichage lettre par lettre du premier `h1` sans boucle, puis enchaîne sur le deuxième `h1` avec l'effet d'effacement et de réaffichage des éléments suivants. Voici comment vous pouvez procéder :

```javascript
var TxtType = function(el, toRotate, period, isLooping) {
    this.toRotate = toRotate;
    this.el = el;
    this.loopNum = 0;
    this.period = parseInt(period, 10) || 2000;
    this.txt = '';
    this.isLooping = isLooping; // Ajout d'un contrôle pour activer ou désactiver la boucle
    this.tick();
    this.isDeleting = false;
};

TxtType.prototype.tick = function() {
    var i = this.loopNum % this.toRotate.length;
    var fullTxt = this.toRotate[i];

    if (this.isDeleting) {
    this.txt = fullTxt.substring(0, this.txt.length - 1);
    } else {
    this.txt = fullTxt.substring(0, this.txt.length + 1);
    }

    this.el.innerHTML = '<span class="wrap">'+this.txt+'</span>';

    var that = this;
    var delta = 200 - Math.random() * 100;

    if (this.isDeleting) { delta /= 2; }

    if (!this.isDeleting && this.txt === fullTxt) {
        if (this.isLooping) { // Vérifier si la boucle est activée
            delta = this.period;
            this.isDeleting = true;
        } else {
            return; // Si la boucle n'est pas activée, arrêter l'animation une fois le texte complet affiché
        }
    } else if (this.isDeleting && this.txt === '') {
        if (this.isLooping) { // Continuer la boucle si elle est activée
            this.isDeleting = false;
            this.loopNum++;
            delta = 500;
        }
    }

    setTimeout(function() {
    that.tick();
    }, delta);
};

window.onload = function() {
    var elements = document.getElementsByClassName('typewrite');
    for (var i=0; i<elements.length; i++) {
        var toRotate = elements[i].getAttribute('data-type');
        var period = elements[i].getAttribute('data-period');
        if (toRotate) {
            new TxtType(elements[i], JSON.parse(toRotate), period, false); // Le dernier paramètre 'false' désactive la boucle pour le premier h1
        }
    }
    var elements2 = document.getElementsByClassName('typewrite2');
    for (var j=0; j<elements2.length; j++) {
        var toRotate2 = elements2[j].getAttribute('data-type');
        var period2 = elements2[j].getAttribute('data-period');
        if (toRotate2) {
